const { exec } = require('child_process');

module.exports = async function(context, req) {
    const inputFilename = req.body.inputFilename;
    const outputFormat = req.body.outputFormat;

    if (!inputFilename || !outputFormat) {
        context.res = {
            status: 400,
            body: "Please provide both inputFilename and outputFormat in the request body."
        };
        return;
    }

    const command = `libreoffice --headless --convert-to ${outputFormat} "${inputFilename}" --outdir /tmp`;

    exec(command, (error, stdout, stderr) => {
        if (error) {
            context.res = {
                status: 500,
                body: `Error executing LibreOffice command: ${stderr || error}`
            };
            return;
        }

        const outputFilename = `${inputFilename.split('.').slice(0, -1).join('.')}.${outputFormat}`;
        context.res = {
            status: 200,
            body: `Document successfully converted to ${outputFilename}`
        };
    });
};